import React from 'react';
import { Card, Stack, Row, Text, Container } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

const getWeatherEmoji = (condition: string): string => {
  const lowerCondition = condition.toLowerCase();
  if (lowerCondition.includes('sunny') || lowerCondition.includes('clear')) return '☀️';
  if (lowerCondition.includes('cloudy') || lowerCondition.includes('overcast')) return '☁️';
  if (lowerCondition.includes('rainy') || lowerCondition.includes('rain')) return '🌧️';
  if (lowerCondition.includes('snowy') || lowerCondition.includes('snow')) return '❄️';
  if (lowerCondition.includes('stormy') || lowerCondition.includes('thunder')) return '⛈️';
  if (lowerCondition.includes('windy') || lowerCondition.includes('wind')) return '💨';
  if (lowerCondition.includes('foggy') || lowerCondition.includes('fog')) return '🌫️';
  return '🌤️';
};

const getSmallWeatherEmoji = (icon?: string): string => {
  if (!icon) return '🌤️';
  const lowerIcon = icon.toLowerCase();
  if (lowerIcon.includes('sunny') || lowerIcon.includes('clear')) return '☀️';
  if (lowerIcon.includes('cloudy') || lowerIcon.includes('cloud')) return '☁️';
  if (lowerIcon.includes('rain')) return '🌧️';
  if (lowerIcon.includes('snow')) return '❄️';
  if (lowerIcon.includes('storm') || lowerIcon.includes('thunder')) return '⛈️';
  if (lowerIcon.includes('wind')) return '💨';
  if (lowerIcon.includes('fog')) return '🌫️';
  return '🌤️';
};

export default function GeneratedComponent({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit = 'C',
  forecast = [],
}: Props) {
  return (
    <Container maxWidth="md" padding="24">
      <Card padding="24" shadow="md">
        <Stack direction="vertical" gap={24}>
          {/* Header with city name */}
          <Text variant="h2" color="var(--ggui-color-onSurface)">{city}</Text>

          {/* Current weather section */}
          <Stack direction="vertical" gap={16} align="center">
            {/* Large temperature display */}
            <Text
              variant="h1"
              color="var(--ggui-color-primary-600)"
              weight="bold"
              align="center"
            >
              {temperature}°{unit}
            </Text>

            {/* Weather condition with emoji */}
            <Row gap={8} align="center" justify="center">
              <Text
                variant="h3"
                color="var(--ggui-color-onSurface)"
                weight="medium"
              >
                <span style={{ fontSize: '2rem', marginRight: 'var(--ggui-spacing-2, 8px)' }}>
                  {getWeatherEmoji(condition)}
                </span>
                {condition}
              </Text>
            </Row>
          </Stack>

          {/* Details row: humidity and wind speed */}
          <Row gap={16} justify="between" align="stretch">
            {/* Humidity */}
            <div
              style={{
                flex: 1,
                padding: 'var(--ggui-spacing-4, 16px)',
                backgroundColor: 'var(--ggui-color-surfaceVariant)',
                borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                display: 'flex',
                flexDirection: 'column',
                alignItems: 'center',
                gap: 'var(--ggui-spacing-2, 8px)',
              }}
            >
              <Text
                variant="caption"
                color="var(--ggui-color-onSurfaceVariant)"
                weight="medium"
              >
                💧 Humidity
              </Text>
              <Text
                variant="h3"
                color="var(--ggui-color-onSurface)"
                weight="semibold"
              >
                {humidity}%
              </Text>
            </div>

            {/* Wind speed */}
            <div
              style={{
                flex: 1,
                padding: 'var(--ggui-spacing-4, 16px)',
                backgroundColor: 'var(--ggui-color-surfaceVariant)',
                borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                display: 'flex',
                flexDirection: 'column',
                alignItems: 'center',
                gap: 'var(--ggui-spacing-2, 8px)',
              }}
            >
              <Text
                variant="caption"
                color="var(--ggui-color-onSurfaceVariant)"
                weight="medium"
              >
                💨 Wind Speed
              </Text>
              <Text
                variant="h3"
                color="var(--ggui-color-onSurface)"
                weight="semibold"
              >
                {windSpeed} km/h
              </Text>
            </div>
          </Row>

          {/* Divider line */}
          <div
            style={{
              height: '1px',
              backgroundColor: 'var(--ggui-color-outline)',
            }}
          />

          {/* 5-day forecast strip */}
          <Stack direction="vertical" gap={12}>
            <Text
              variant="label"
              color="var(--ggui-color-onSurfaceVariant)"
              weight="medium"
            >
              5-Day Forecast
            </Text>

            <Row gap={8} wrap justify="between">
              {forecast.map((day, index) => (
                <div
                  key={index}
                  style={{
                    flex: '1 1 calc(20% - 8px)',
                    minWidth: '80px',
                    padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-2, 8px)',
                    backgroundColor: 'var(--ggui-color-container)',
                    borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                    display: 'flex',
                    flexDirection: 'column',
                    alignItems: 'center',
                    gap: 'var(--ggui-spacing-1, 4px)',
                    textAlign: 'center',
                  }}
                >
                  {/* Day name */}
                  {day.day && (
                    <Text
                      variant="caption"
                      color="var(--ggui-color-onContainer)"
                      weight="medium"
                    >
                      {day.day}
                    </Text>
                  )}

                  {/* Weather icon/emoji */}
                  <Text style={{ fontSize: '1.5rem' }}>
                    {getSmallWeatherEmoji(day.icon)}
                  </Text>

                  {/* High/Low temperatures */}
                  <div style={{ display: 'flex', gap: 'var(--ggui-spacing-1, 4px)', fontSize: '12px' }}>
                    {day.high !== undefined && (
                      <Text
                        variant="caption"
                        color="var(--ggui-color-onContainer)"
                        weight="semibold"
                      >
                        {day.high}°
                      </Text>
                    )}
                    {day.low !== undefined && (
                      <Text
                        variant="caption"
                        color="var(--ggui-color-onContainer)"
                        weight="normal"
                      >
                        {day.low}°
                      </Text>
                    )}
                  </div>
                </div>
              ))}
            </Row>
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}
